const input = $input.first().json;
const body = input.body ?? input;
const expectedToken = String($env.YOUTUBE_PUBLISH_APPROVAL_TOKEN || '').trim();
const providedToken = String(body.approvalToken || body.publishApprovalToken || '').trim();
const publishApproved = Boolean(expectedToken && providedToken && providedToken === expectedToken && body.confirm === 'publish-to-youtube');
const uploadEnabled = false;

function text(value) {
  return typeof value === 'string' ? value.trim() : '';
}

function firstText(...values) {
  for (const value of values) {
    const result = text(value);
    if (result) return result;
  }
  return '';
}

function clamp(value, max) {
  const result = text(value);
  return result.length > max ? result.slice(0, max).trim() : result;
}

function arrayFrom(value) {
  if (Array.isArray(value)) return value;
  return String(value || '').split(',');
}

const artifacts = body.artifacts || {};
const metadata = body.metadata || {};
const youtubeMetadata = metadata.youtube && typeof metadata.youtube === 'object' && !Array.isArray(metadata.youtube) ? metadata.youtube : {};
const publishingMetadata = metadata.publishing && typeof metadata.publishing === 'object' && !Array.isArray(metadata.publishing) ? metadata.publishing : {};
const requestId = firstText(body.requestId, metadata.requestId);
const artifactPageUrl = firstText(body.artifactPageUrl, artifacts.pageUrl, artifacts.artifactPageUrl);
const finalVideoUrl = firstText(body.finalVideoUrl, artifacts.finalVideoUrl, artifacts.mp4Url, artifacts.videoUrl);
const thumbnailUrl = firstText(body.thumbnailUrl, artifacts.thumbnailUrl);
const title = clamp(firstText(body.title, youtubeMetadata.title, publishingMetadata.title, metadata.title), 100);
const descriptionBase = firstText(body.description, youtubeMetadata.description, publishingMetadata.description, metadata.description);
const sourceLine = artifactPageUrl ? `\n\nSource artifact package: ${artifactPageUrl}` : '';
const description = clamp(`${descriptionBase}${sourceLine}`, 5000);
const metadataTags = Array.isArray(youtubeMetadata.tags) ? youtubeMetadata.tags : (Array.isArray(publishingMetadata.tags) ? publishingMetadata.tags : arrayFrom(youtubeMetadata.tags || publishingMetadata.tags || metadata.tags));
const tags = Array.isArray(body.tags) ? body.tags : metadataTags;
const cleanTags = [...new Set(tags.map((tag) => text(tag)).filter(Boolean))].slice(0, 25);
const privacyStatus = ['private', 'unlisted', 'public'].includes(body.privacyStatus) ? body.privacyStatus : (['private', 'unlisted', 'public'].includes(youtubeMetadata.privacyStatus) ? youtubeMetadata.privacyStatus : 'private');
const categoryId = String(body.categoryId || youtubeMetadata.categoryId || '10');
const regionCode = String(body.regionCode || youtubeMetadata.regionCode || 'VN');
const madeForKids = Boolean(body.madeForKids || youtubeMetadata.madeForKids || false);
const duplicateKey = firstText(body.duplicateKey, publishingMetadata.duplicateKey, requestId);

let duplicateRecord = null;
let ledgerAvailable = false;
try {
  const workflowStatic = typeof $getWorkflowStaticData === 'function' ? $getWorkflowStaticData('global') : null;
  const ledger = workflowStatic && workflowStatic.youtubePublishLedger && typeof workflowStatic.youtubePublishLedger === 'object'
    ? workflowStatic.youtubePublishLedger
    : {};
  ledgerAvailable = Boolean(workflowStatic);
  duplicateRecord = duplicateKey && ledger[duplicateKey] ? ledger[duplicateKey] : null;
} catch (error) {
  ledgerAvailable = false;
}

const missing = [];
if (!requestId) missing.push('requestId');
if (!artifactPageUrl) missing.push('artifactPageUrl');
if (!finalVideoUrl) missing.push('finalVideoUrl');
if (!thumbnailUrl) missing.push('thumbnailUrl');
if (!title) missing.push('title');
if (!descriptionBase) missing.push('description');

const gateBlocks = [];
if (missing.length) gateBlocks.push(`missing:${missing.join(',')}`);
if (!publishApproved) gateBlocks.push('approval_required');
if (duplicateRecord) gateBlocks.push('duplicate_publish_key');
if (!uploadEnabled) gateBlocks.push('upload_branch_disabled');

const ok = missing.length === 0;
const readyForUpload = ok && publishApproved && !duplicateRecord && uploadEnabled;
const responseCode = ok ? (duplicateRecord ? 409 : 200) : 400;
const status = !ok ? 'invalid_package' : duplicateRecord ? 'duplicate_blocked' : publishApproved ? 'approved_preflight_only' : 'preflight_only';

return [{ json: {
  ok,
  responseCode,
  status,
  requestId,
  publishApproved,
  uploadEnabled,
  readyForUpload,
  duplicate: Boolean(duplicateRecord),
  duplicateRecord,
  ledgerAvailable,
  gateBlocks,
  message: ok
    ? (duplicateRecord
      ? `Duplicate publish blocked for key: ${duplicateKey}`
      : (publishApproved ? 'Package passed validation and explicit approval. Upload remains disabled until the final publish switch is enabled.' : 'Package passed validation. Upload requires confirm=publish-to-youtube and approvalToken.'))
    : `Package is missing required fields: ${missing.join(', ')}`,
  missing,
  uploadPlan: {
    requestId,
    duplicateKey,
    finalVideoUrl,
    thumbnailUrl,
    artifactPageUrl,
    title,
    description,
    tags: cleanTags,
    tagsCsv: cleanTags.join(','),
    privacyStatus,
    categoryId,
    regionCode,
    madeForKids,
    notifySubscribers: false
  },
  thumbnailPlan: {
    sourceUrl: thumbnailUrl,
    requiresVideoId: true,
    endpoint: 'https://www.googleapis.com/upload/youtube/v3/thumbnails/set',
    stagedNode: 'Set YouTube Thumbnail (disabled)'
  },
  rollbackPlan: {
    deleteUploadedVideo: 'Use YouTube video delete by videoId if an accidental upload occurs.',
    clearLedgerKey: duplicateKey ? `Remove youtubePublishLedger[${duplicateKey}] from workflow static data only after confirming YouTube rollback.` : '',
    keepSourceArtifact: artifactPageUrl
  }
} }];

const item = $input.first().json;
const uploadPlan = item.uploadPlan || {};
const key = String(uploadPlan.duplicateKey || item.requestId || '').trim();
if (!key) {
  throw new Error('Cannot record YouTube publish ledger without duplicateKey');
}
const workflowStatic = $getWorkflowStaticData('global');
workflowStatic.youtubePublishLedger = workflowStatic.youtubePublishLedger || {};
workflowStatic.youtubePublishLedger[key] = {
  requestId: uploadPlan.requestId || item.requestId || key,
  videoId: item.id || item.videoId || item.uploadResult?.id || null,
  title: uploadPlan.title || null,
  artifactPageUrl: uploadPlan.artifactPageUrl || null,
  recordedAt: new Date().toISOString()
};
return [{ json: { ...item, ledgerRecorded: true, ledgerKey: key } }];
